// bannerSideText is printed to the right of the mark, one entry per art row it
// annotates, starting at bannerSideStartRow. %s in the version line is filled
// at print time.
var bannerSideText = []string{
	"\x1b[1;38;2;43;144;255mCrewship\x1b[0m",
	"\x1b[2mSelf-hosted runtime for AI coding agents\x1b[0m",
	"",
	"\x1b[2m%s\x1b[0m",
}

const bannerSideStartRow = 5

// PrintStartupBanner writes the Crewship brand banner to w, but only when w is
// an interactive, truecolor-capable terminal. It deliberately no-ops for pipes,
// files, NO_COLOR, and non-truecolor terminals â€” the 24-bit half-block art
// would look wrong when downsampled â€” so machine-readable and CI output stays
// clean. version is shown beside the mark (e.g. "v0.1.0" or "dev").
func PrintStartupBanner(w io.Writer, version string) {
	if !bannerCapable(w) {
		return
	}
	fmt.Fprintln(w)
	for i, row := range crewshipBannerArt {
		side := ""
		if j := i - bannerSideStartRow; j >= 0 && j < len(bannerSideText) {
			txt := bannerSideText[j]
			if version == "" {
				version = "dev"
			}
			txt = fmt.Sprintf(txt, version)
			side = "   " + txt
		}
		fmt.Fprintln(w, row+side)
	}
	fmt.Fprintln(w)
}

// bannerCapable reports whether w is a real terminal that can render 24-bit
// half-block art. It requires an *os.File TTY, NO_COLOR unset, and a truecolor
// COLORTERM â€” the conservative set where the banner is known to look right.
func bannerCapable(w io.Writer) bool {
	if os.Getenv("NO_COLOR") != "" {
		return false
	}
	if ct := os.Getenv("COLORTERM"); ct != "truecolor" && ct != "24bit" {
		return false
	}
	f, ok := w.(*os.File)
	if !ok {
		return false
	}
	return isatty.IsTerminal(f.Fd()) || isatty.IsCygwinTerminal(f.Fd())
}
